package com.example.login;

import android.content.Context;
import android.content.SharedPreferences;

import androidx.annotation.Nullable;

public final class CredentialsStore {
    private static final String PREFS_NAME = "auth_prefs";
    private static final String KEY_EMAIL = "email";
    private static final String KEY_TOKEN = "token";

    private CredentialsStore() {}

    private static SharedPreferences prefs(Context context) {
        return context.getApplicationContext().getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    public static void save(Context context, String email, String token) {
        prefs(context).edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    public static boolean hasCredentials(Context context) {
        String token = prefs(context).getString(KEY_TOKEN, null);
        return token != null && !token.trim().isEmpty();
    }

    @Nullable
    public static String getEmail(Context context) {
        return prefs(context).getString(KEY_EMAIL, null);
    }

    @Nullable
    public static String getToken(Context context) {
        return prefs(context).getString(KEY_TOKEN, null);
    }

    public static void clear(Context context) {
        prefs(context).edit().clear().apply();
    }
}

package com.example.login;

public final class AuthResult {
    public final boolean success;
    public final String email;
    public final String token;
    public final String errorMessage;

    private AuthResult(boolean success, String email, String token, String errorMessage) {
        this.success = success;
        this.email = email;
        this.token = token;
        this.errorMessage = errorMessage;
    }

    public static AuthResult success(String email, String token) {
        return new AuthResult(true, email, token, null);
    }

    public static AuthResult error(String message) {
        return new AuthResult(false, null, null, message);
    }
}

package com.example.login;

import android.os.Handler;
import android.os.Looper;

import androidx.annotation.NonNull;

import java.util.UUID;

public final class AuthService {

    public interface Callback {
        void onResult(@NonNull AuthResult result);
    }

    private final Handler mainHandler = new Handler(Looper.getMainLooper());

    public void login(@NonNull final String email, @NonNull final String password, @NonNull final Callback callback) {
        mainHandler.postDelayed(() -> {
            if (email.trim().isEmpty() || password.trim().isEmpty()) {
                callback.onResult(AuthResult.error("Email and password are required"));
                return;
            }
            if (!email.contains("@")) {
                callback.onResult(AuthResult.error("Invalid email"));
                return;
            }
            String token = "demo_" + UUID.randomUUID().toString();
            callback.onResult(AuthResult.success(email.trim(), token));
        }, 700);
    }
}

package com.example.login;

import android.content.Intent;
import android.os.Bundle;
import android.text.InputType;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;
    private ProgressBar progress;
    private TextView errorText;

    private final AuthService authService = new AuthService();

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (CredentialsStore.hasCredentials(this)) {
            startActivity(new Intent(this, HomeActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);
        progress = findViewById(R.id.progress);
        errorText = findViewById(R.id.errorText);

        passwordInput.setInputType(InputType.TYPE_CLASS_TEXT | InputType.TYPE_TEXT_VARIATION_PASSWORD);

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void attemptLogin() {
        setLoading(true);
        setError(null);

        final String email = emailInput.getText() != null ? emailInput.getText().toString() : "";
        final String password = passwordInput.getText() != null ? passwordInput.getText().toString() : "";

        authService.login(email, password, result -> {
            if (result.success) {
                CredentialsStore.save(LoginActivity.this, result.email, result.token);
                startActivity(new Intent(LoginActivity.this, HomeActivity.class));
                finish();
            } else {
                setLoading(false);
                setError(result.errorMessage != null ? result.errorMessage : "Login failed");
            }
        });
    }

    private void setLoading(boolean loading) {
        progress.setVisibility(loading ? View.VISIBLE : View.GONE);
        loginButton.setEnabled(!loading);
        emailInput.setEnabled(!loading);
        passwordInput.setEnabled(!loading);
    }

    private void setError(@Nullable String message) {
        if (message == null || message.trim().isEmpty()) {
            errorText.setVisibility(View.GONE);
            errorText.setText("");
        } else {
            errorText.setVisibility(View.VISIBLE);
            errorText.setText(message);
        }
    }
}

package com.example.login;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private TextView welcomeText;
    private TextView tokenText;
    private Button logoutButton;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        if (!CredentialsStore.hasCredentials(this)) {
            startActivity(new Intent(this, LoginActivity.class));
            finish();
            return;
        }

        setContentView(R.layout.activity_home);

        welcomeText = findViewById(R.id.welcomeText);
        tokenText = findViewById(R.id.tokenText);
        logoutButton = findViewById(R.id.logoutButton);

        String email = CredentialsStore.getEmail(this);
        String token = CredentialsStore.getToken(this);

        welcomeText.setText("Welcome" + (email != null ? (", " + email) : ""));
        tokenText.setText(token != null ? ("Token: " + token) : "Token: (none)");

        logoutButton.setOnClickListener(v -> {
            CredentialsStore.clear(HomeActivity.this);
            startActivity(new Intent(HomeActivity.this, LoginActivity.class));
            finish();
        });
    }
}

